import { createClient } from "@clickhouse/client-web";
import { getLogger } from "@logtape/logtape";

const logger = getLogger(["rudel", "api", "clickhouse"]);

export interface ClickHouseExecutor {
	execute(sql: string): Promise<void>;
	query<T>(sql: string): Promise<T[]>;
	insert(params: { table: string; values: object[] }): Promise<void>;
}

export function createClickHouseExecutor(config: {
	url: string;
	username?: string;
	password?: string;
	database?: string;
}): ClickHouseExecutor {
	const client = createClient({
		url: config.url,
		username: config.username,
		password: config.password,
		database: config.database,
		request_timeout: 120_000,
		clickhouse_settings: {
			wait_end_of_query: 1,
			output_format_json_quote_64bit_integers: 0,
		},
	});
	return {
		async execute(sql) {
			await client.command({ query: sql });
		},
		async query<T>(sql: string): Promise<T[]> {
			const result = await client.query({
				query: sql,
				format: "JSONEachRow",
			});
			return result.json();
		},
		async insert(params) {
			// Use command() with FORMAT JSONEachRow instead of client.insert()
			// because ClickHouse Cloud's @clickhouse/client insert() silently drops data.
			const rows = params.values.map((r) => JSON.stringify(r)).join("\n");
			await client.command({
				query: `INSERT INTO ${params.table} SETTINGS async_insert=0 FORMAT JSONEachRow ${rows}`,
			});
		},
	};
}

let _clickhouse: ClickHouseExecutor | null = null;

export function getClickhouse(): ClickHouseExecutor {
	if (!_clickhouse) {
		const executor = createClickHouseExecutor({
			url: process.env.CLICKHOUSE_URL || "http://localhost:8123",
			username:
				process.env.CLICKHOUSE_USERNAME ||
				process.env.CLICKHOUSE_USER ||
				"default",
			password: process.env.CLICKHOUSE_PASSWORD || "",
			database: "default",
		});
		const maxRetries = 3;
		_clickhouse = {
			...executor,
			async insert(params) {
				for (let attempt = 0; attempt < maxRetries; attempt++) {
					try {
						return await executor.insert(params);
					} catch (error) {
						if (attempt === maxRetries - 1) {
							logger.error(
								"Insert into {table} failed after {maxRetries} attempts: {error}",
								{ table: params.table, maxRetries, error },
							);
							throw error;
						}
						logger.warn(
							"Insert into {table} failed (attempt {attempt}/{maxRetries}), retrying: {error}",
							{
								table: params.table,
								attempt: attempt + 1,
								maxRetries,
								error,
							},
						);
						await new Promise((r) => setTimeout(r, 100 * (attempt + 1)));
					}
				}
			},
		};
	}
	return _clickhouse;
}

export function escapeString(value: string): string {
	return value.replace(/'/g, "\\'");
}

export function buildDateFilter(days: number, column = "session_date"): string {
	return `${column} >= now64(3) - INTERVAL ${Number(days)} DAY AND ${column} <= now64(3)`;
}

export async function queryClickhouse<T>(sql: string): Promise<T[]> {
	const ch = getClickhouse();
	return ch.query<T>(sql);
}

import type {
	DeveloperDetails as DeveloperDetailsBase,
	DeveloperError,
	DeveloperFeatureUsage,
	DeveloperProject as DeveloperProjectBase,
	DeveloperSession as DeveloperSessionBase,
	DeveloperSummary as DeveloperSummaryBase,
	DeveloperTimeline,
	DeveloperTrendDataPoint,
} from "@rudel/api-routes";
import {
	buildDateFilter,
	escapeString,
	queryClickhouse,
} from "../clickhouse.js";

export interface DeveloperSummary extends DeveloperSummaryBase {
	username?: string;
}

export interface DeveloperDetails extends DeveloperDetailsBase {
	username?: string;
}

export interface DeveloperSession extends DeveloperSessionBase {
	project_name?: string;
	input_tokens: number;
	output_tokens: number;
}

export interface DeveloperProject extends DeveloperProjectBase {
	project_name?: string;
}

export interface DeveloperProjectTimeline {
	date: string;
	project_path: string;
	sessions: number;
	total_duration_min: number;
	total_tokens: number;
}

/**
 * Extract project name from path (last segment)
 */
function extractProjectName(projectPath: string): string {
	if (!projectPath) return "";
	const segments = projectPath.replace(/\\/g, "/").split("/").filter(Boolean);
	return segments[segments.length - 1] || projectPath;
}

/**
 * Get list of all developers with summary stats
 */
export async function getDeveloperList(
	orgId: string,
	days = 30,
): Promise<DeveloperSummary[]> {
	const org = escapeString(orgId);
	const d = Number(days);

	const query = `
    WITH current_period AS (
      SELECT
        user_id,
        COUNT(*) as total_sessions,
        COUNT(DISTINCT toDate(session_date)) as active_days,
        SUM(ifNull(input_tokens, 0)) as input_tokens_sum,
        SUM(ifNull(output_tokens, 0)) as output_tokens_sum,
        SUM(ifNull(input_tokens, 0) + ifNull(output_tokens, 0)) as total_tokens,
        round(SUM(actual_duration_min), 2) as total_duration_min,
        round(AVG(actual_duration_min), 2) as avg_session_duration_min,
        toString(max(session_date)) as last_active_date,
        round(AVG(success_score), 2) as success_rate
      FROM rudel.session_analytics
      WHERE ${buildDateFilter(d)}
        AND organization_id = '${org}'
      GROUP BY user_id
    ),
    previous_period AS (
      SELECT
        user_id,
        round(AVG(success_score), 2) as prev_success_rate
      FROM rudel.session_analytics
      WHERE session_date >= now64(3) - INTERVAL ${d * 2} DAY
        AND session_date < now64(3) - INTERVAL ${d} DAY
        AND organization_id = '${org}'
      GROUP BY user_id
    )
    SELECT
      c.user_id,
      c.total_sessions,
      c.active_days,
      c.total_tokens,
      c.input_tokens_sum as input_tokens,
      c.output_tokens_sum as output_tokens,
      c.total_duration_min,
      c.avg_session_duration_min,
      c.last_active_date,
      c.success_rate,
      round((c.output_tokens_sum * 0.000015) + (c.input_tokens_sum * 0.000003), 4) as cost,
      round(c.success_rate - ifNull(p.prev_success_rate, c.success_rate), 2) as success_rate_trend
    FROM current_period c
    LEFT JOIN previous_period p ON c.user_id = p.user_id
    ORDER BY c.total_sessions DESC
  `;

	return queryClickhouse<DeveloperSummary>(query);
}

/**
 * Get detailed metrics for a specific developer
 */
export async function getDeveloperDetails(
	orgId: string,
	userId: string,
	days = 30,
): Promise<DeveloperDetails | null> {
	const org = escapeString(orgId);
	const uid = escapeString(userId);
	const d = Number(days);

	const query = `
    WITH current_period AS (
      SELECT
        user_id,
        COUNT(*) as total_sessions,
        COUNT(DISTINCT toDate(session_date)) as active_days,
        SUM(ifNull(input_tokens, 0) + ifNull(output_tokens, 0)) as total_tokens,
        SUM(ifNull(input_tokens, 0)) as input_tokens_sum,
        SUM(ifNull(output_tokens, 0)) as output_tokens_sum,
        round(SUM(actual_duration_min), 2) as total_duration_min,
        round(AVG(actual_duration_min), 2) as avg_session_duration_min,
        toString(max(session_date)) as last_active_date,
        round(AVG(success_score), 2) as success_rate,
        COUNT(DISTINCT project_path) as distinct_projects,
        SUM(error_count) as error_count
      FROM rudel.session_analytics
      WHERE user_id = '${uid}'
        AND ${buildDateFilter(d)}
        AND organization_id = '${org}'
      GROUP BY user_id
    ),
    previous_period AS (
      SELECT
        user_id,
        round(AVG(success_score), 2) as prev_success_rate
      FROM rudel.session_analytics
      WHERE user_id = '${uid}'
        AND session_date >= now64(3) - INTERVAL ${d * 2} DAY
        AND session_date < now64(3) - INTERVAL ${d} DAY
        AND organization_id = '${org}'
      GROUP BY user_id
    )
    SELECT
      c.user_id,
      c.total_sessions,
      c.active_days,
      c.total_tokens,
      c.input_tokens_sum as input_tokens,
      c.output_tokens_sum as output_tokens,
      c.total_duration_min,
      c.avg_session_duration_min,
      c.last_active_date,
      c.success_rate,
      round((c.output_tokens_sum * 0.000015) + (c.input_tokens_sum * 0.000003), 4) as cost,
      round(c.success_rate - ifNull(p.prev_success_rate, c.success_rate), 2) as success_rate_trend,
      c.distinct_projects,
      c.error_count
    FROM current_period c
    LEFT JOIN previous_period p ON c.user_id = p.user_id
  `;

	const results = await queryClickhouse<DeveloperDetails>(query);
	const [first] = results;
	if (!first) return null;

	return first;
}
